jQuery(document).ready(function() {
    var chaine5 = '';
    for (var i = 0 ; i < 5 ; i++)
        chaine5+=Math.floor((Math.random() * 9) + 1);;

  jQuery('#inlineTextKeypad').keypad({
    onKeypress : appendValue,
    showOn : 'both',
    showAnim : 'slide',
    buttonImageOnly : true,
    //buttonImage : [[@{/images/small-keyboard.png}]],
    randomiseNumeric : true,
    layout : [ '01234', '56789', chaine5 ]
  });

  function appendValue(key) {
    var field = jQuery("input[name='password']");
    if (typeof key == "undefined") { // boutton supprimer
      var fieldvalue = field.val()
      field.val(fieldvalue.substring(0, fieldvalue.length - 1));
    } else {

      jQuery.keypad.insertValue(field, key);
      field.focus();
    }
  }


function setupBanniere(url){
    $.ajax({
        url: url
    }).then(function(data) {

       $('#banniere_image').prepend('<img src="'+data.imageUrl+'"/>');
       $('#titre').html(data.title);
       $('#description').html(data.description);
    });
}

});

$('#clear_input').click(function () {
    $('#password').focus();
    $('#password').val('');
    $('#pswd').focus();
    $('#pswd').val('');
});

$('#delete_input').click(function () {
    var fieldN = jQuery("input[name='password']");
    var fieldK = jQuery("input[name='pswd']");
    var fieldvalue = fieldN.val().substring(0, fieldN.val().length-1);
    var fieldKvalue = fieldK.val().substring(0, fieldK.val().length-8);
    fieldN.val(fieldvalue);
    fieldK.val(fieldKvalue);
    fieldN.focus();
});

function appendValue(key) {
    var fieldN = jQuery("input[name='password']");
    var fieldK = jQuery("input[name='pswd']");
    var fieldvalue = fieldN.val();
    fieldN.val(fieldvalue + "*" );
    fieldK.val(fieldK.val() + "" + key);
    fieldN.focus();
}
function sendValue(matrice) {
    var fieldN = jQuery("input[name='password']");
    var fieldK = jQuery("input[name='pswd']");
    var token = jQuery("input[name='token']");

    var iv = CryptoJS.lib.WordArray.random(128/8).toString(CryptoJS.enc.Hex);
    var salt = CryptoJS.lib.WordArray.random(128/8).toString(CryptoJS.enc.Hex);

    var aesUtil = new AesUtil(128, 1000);
    var ciphertext = aesUtil.encrypt(salt, iv, token.val(), fieldK.val());

    var aesPassword = (iv + "::" + salt + "::" + ciphertext);
    var password = btoa(aesPassword);

    fieldK.val(password);

}

function setupCmsContent(url){
    $.ajax({
        url: url
    }).then(function(posts) {
     $.each(posts, function() {
        if(this.category!=null && this.category=='feature'){
         $('#'+this.id+' h4').html(this.title);
         $('#'+this.id+' img').attr("src", this.imageUrl)
         $('#'+this.id+' p').html(marked(this.description));
        }
        else if(this.category!=null && this.category=='faq'){
          $('#'+this.id+' h4').html(this.title);
          $('#'+this.id+' p').html(marked(this.description));
         }
          else if(this.id=='FeaturesList'){
            $('.feature-detail h3').html(this.title);
            $('.feature-detail .zmdi-hc-ul').html(marked(this.description));
            $('#feature-details-img').attr("src", this.imageUrl)
          }
          else if(this.id=='LoginPitch'){
            $('.home-wrapper > h2').html(this.title);
            $('.home-wrapper > p').html(marked(this.description));
          }
       });

    });
}

var div = document.getElementById('padDiv');
var marginL = Math.floor((Math.random() * 80) + 1);
var marginR = Math.floor((Math.random() * 80) + 1);
var marginT = Math.floor((Math.random() * 0) + 1);
div.style.marginBottom = 0+'px';
div.style.marginLeft = marginL+'px';
div.style.marginRight = marginR+'px';
div.style.marginTop= marginT+'px';
div.style.width = 180+'px';
